-- correct_answer oculto 42501). ids uuid5. audio_url → audio/stories/<id>_<i>.mp3.
begin;
insert into stories (id, course_id, cefr_level, order_index, title, subtitle, emoji, intro, est_seconds, segments, glossary, questions) values
('12ce096e-9f00-56b5-8adb-41b638e34283'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'A1',1,$p$A padaria da Ana$p$,$p$Ana va a la panadería en Río de Janeiro para desayunar.$p$,$p$🥐$p$,$p$Es una mañana en Río de Janeiro. Ana sale de casa para desayunar en su panadería favorita. Lee y escucha su pequeña historia.$p$,56,$j$[{"en": "Oi! Eu me chamo Ana.", "es": "¡Hola! Me llamo Ana.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/12ce096e-9f00-56b5-8adb-41b638e34283-0.mp3"}, {"en": "Eu moro no Rio de Janeiro com a minha família.", "es": "Vivo en Río de Janeiro con mi familia.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/12ce096e-9f00-56b5-8adb-41b638e34283-1.mp3"}, {"en": "De manhã, eu vou à padaria perto de casa.", "es": "Por la mañana, voy a la panadería cerca de casa.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/12ce096e-9f00-56b5-8adb-41b638e34283-2.mp3"}, {"en": "O atendente pergunta: «Bom dia! O que você quer?»", "es": "El empleado pregunta: «¡Buenos días! ¿Qué quieres?»", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/12ce096e-9f00-56b5-8adb-41b638e34283-3.mp3"}, {"en": "Eu queria um café com leite e um pão de queijo.", "es": "Quería un café con leche y un pan de queso.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/12ce096e-9f00-56b5-8adb-41b638e34283-4.mp3"}, {"en": "O pão de queijo é quentinho e muito gostoso.", "es": "El pan de queso está calentito y muy rico.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/12ce096e-9f00-56b5-8adb-41b638e34283-5.mp3"}, {"en": "Obrigada! Até amanhã!", "es": "¡Gracias! ¡Hasta mañana!", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/12ce096e-9f00-56b5-8adb-41b638e34283-6.mp3"}]$j$::jsonb,$j$[{"word": "oi", "translation": "hola"}, {"word": "a padaria", "translation": "la panadería"}, {"word": "de manhã", "translation": "por la mañana"}, {"word": "o café com leite", "translation": "el café con leche"}, {"word": "o pão de queijo", "translation": "el pan de queso (típico brasileño)"}, {"word": "quentinho", "translation": "calentito"}, {"word": "gostoso", "translation": "rico / sabroso"}]$j$::jsonb,$j$[{"type": "multiple_choice", "skill": "reading", "prompt": "¿Cómo se llama la protagonista?", "payload": {"options": ["Ana", "Maria", "Júlia"]}, "difficulty": 0.2, "correct_answer": {"value": "Ana"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿En qué ciudad vive?", "payload": {"options": ["São Paulo", "Rio de Janeiro", "Salvador"]}, "difficulty": 0.2, "correct_answer": {"value": "Rio de Janeiro"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Adónde va por la mañana?", "payload": {"options": ["à padaria", "à praia", "ao trabalho"]}, "difficulty": 0.2, "correct_answer": {"value": "à padaria"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Qué pide?", "payload": {"options": ["um café com leite e um pão de queijo", "um suco e uma torta", "um chá e um pão"]}, "difficulty": 0.2, "correct_answer": {"value": "um café com leite e um pão de queijo"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Cómo está el pão de queijo?", "payload": {"options": ["quentinho", "frio", "ruim"]}, "difficulty": 0.2, "correct_answer": {"value": "quentinho"}}]$j$::jsonb),
('3f49d796-06f0-5ed0-8ab0-b56766b34d82'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'A1',1,$p$Beim Bäcker$p$,$p$Max va a la panadería en Berlín por la mañana.$p$,$p$🥨$p$,$p$Es una mañana en Berlín. Max sale a comprar el desayuno en la panadería de su barrio. Lee y escucha su pequeña historia.$p$,56,$j$[{"en": "Hallo! Ich heiße Max.", "es": "¡Hola! Me llamo Max.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/3f49d796-06f0-5ed0-8ab0-b56766b34d82-0.mp3"}, {"en": "Ich wohne in Berlin mit meiner Familie.", "es": "Vivo en Berlín con mi familia.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/3f49d796-06f0-5ed0-8ab0-b56766b34d82-1.mp3"}, {"en": "Am Morgen gehe ich zur Bäckerei.", "es": "Por la mañana voy a la panadería.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/3f49d796-06f0-5ed0-8ab0-b56766b34d82-2.mp3"}, {"en": "Der Verkäufer sagt: «Guten Morgen! Was möchten Sie?»", "es": "El vendedor dice: «¡Buenos días! ¿Qué desea?»", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/3f49d796-06f0-5ed0-8ab0-b56766b34d82-3.mp3"}, {"en": "Ich möchte einen Kaffee und ein Brötchen.", "es": "Quiero un café y un panecillo.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/3f49d796-06f0-5ed0-8ab0-b56766b34d82-4.mp3"}, {"en": "Das Brötchen ist frisch und der Kaffee ist warm.", "es": "El panecillo está fresco y el café está caliente.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/3f49d796-06f0-5ed0-8ab0-b56766b34d82-5.mp3"}, {"en": "Danke schön! Auf Wiedersehen!", "es": "¡Muchas gracias! ¡Adiós!", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/3f49d796-06f0-5ed0-8ab0-b56766b34d82-6.mp3"}]$j$::jsonb,$j$[{"word": "hallo", "translation": "hola"}, {"word": "die Bäckerei", "translation": "la panadería"}, {"word": "am Morgen", "translation": "por la mañana"}, {"word": "der Kaffee", "translation": "el café"}, {"word": "das Brötchen", "translation": "el panecillo"}, {"word": "frisch", "translation": "fresco"}]$j$::jsonb,$j$[{"type": "multiple_choice", "skill": "reading", "prompt": "¿Cómo se llama el protagonista?", "payload": {"options": ["Max", "Tom", "Paul"]}, "difficulty": 0.2, "correct_answer": {"value": "Max"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿En qué ciudad vive?", "payload": {"options": ["München", "Berlin", "Hamburg"]}, "difficulty": 0.2, "correct_answer": {"value": "Berlin"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Adónde va por la mañana?", "payload": {"options": ["zur Bäckerei", "zur Schule", "ins Büro"]}, "difficulty": 0.2, "correct_answer": {"value": "zur Bäckerei"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Qué quiere?", "payload": {"options": ["einen Kaffee und ein Brötchen", "einen Tee und Kuchen", "eine Suppe"]}, "difficulty": 0.2, "correct_answer": {"value": "einen Kaffee und ein Brötchen"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Cómo está el panecillo?", "payload": {"options": ["frisch", "alt", "kalt"]}, "difficulty": 0.2, "correct_answer": {"value": "frisch"}}]$j$::jsonb),
('9f1bf46b-f890-5b48-890e-7e286000c5ae'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,'A1',1,$p$De koffie van Sanne$p$,$p$Sanne va en bici a un café en Ámsterdam por la mañana.$p$,$p$🚲$p$,$p$Es una mañana en Ámsterdam. Sanne coge la bici y va a su café favorito a desayunar. Lee y escucha su pequeña historia.$p$,56,$j$[{"en": "Hallo! Ik heet Sanne.", "es": "¡Hola! Me llamo Sanne.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9f1bf46b-f890-5b48-890e-7e286000c5ae-0.mp3"}, {"en": "Ik woon in Amsterdam met mijn familie.", "es": "Vivo en Ámsterdam con mi familia.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9f1bf46b-f890-5b48-890e-7e286000c5ae-1.mp3"}, {"en": "'s Morgens ga ik met de fiets naar het café.", "es": "Por la mañana voy en bici al café.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9f1bf46b-f890-5b48-890e-7e286000c5ae-2.mp3"}, {"en": "De ober vraagt: «Goedemorgen! Wat wil je?»", "es": "El camarero pregunta: «¡Buenos días! ¿Qué quieres?»", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9f1bf46b-f890-5b48-890e-7e286000c5ae-3.mp3"}, {"en": "Ik wil graag een koffie en een broodje.", "es": "Quiero un café y un bocadillo.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9f1bf46b-f890-5b48-890e-7e286000c5ae-4.mp3"}, {"en": "Het broodje is lekker en de koffie is warm.", "es": "El bocadillo está rico y el café está caliente.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9f1bf46b-f890-5b48-890e-7e286000c5ae-5.mp3"}, {"en": "Dank je wel! Tot morgen!", "es": "¡Muchas gracias! ¡Hasta mañana!", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9f1bf46b-f890-5b48-890e-7e286000c5ae-6.mp3"}]$j$::jsonb,$j$[{"word": "hallo", "translation": "hola"}, {"word": "het café", "translation": "el café (local)"}, {"word": "de fiets", "translation": "la bicicleta"}, {"word": "de koffie", "translation": "el café (bebida)"}, {"word": "het broodje", "translation": "el bocadillo"}, {"word": "lekker", "translation": "rico / sabroso"}]$j$::jsonb,$j$[{"type": "multiple_choice", "skill": "reading", "prompt": "¿Cómo se llama la protagonista?", "payload": {"options": ["Sanne", "Emma", "Lisa"]}, "difficulty": 0.2, "correct_answer": {"value": "Sanne"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿En qué ciudad vive?", "payload": {"options": ["Rotterdam", "Amsterdam", "Utrecht"]}, "difficulty": 0.2, "correct_answer": {"value": "Amsterdam"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Cómo va al café?", "payload": {"options": ["met de fiets", "met de auto", "met de bus"]}, "difficulty": 0.2, "correct_answer": {"value": "met de fiets"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Qué quiere?", "payload": {"options": ["een koffie en een broodje", "een thee en taart", "een sap"]}, "difficulty": 0.2, "correct_answer": {"value": "een koffie en een broodje"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Cómo está el bocadillo?", "payload": {"options": ["lekker", "koud", "oud"]}, "difficulty": 0.2, "correct_answer": {"value": "lekker"}}]$j$::jsonb)
